/**
 * Normalize `docs.config.js` into the internal shape consumed by buildDocusaurusConfig.
 *
 * Supported nav item shapes:
 *   { label, docsPath, position? }                          -> autogenerated docSidebar scoped to <mdxRoot>/<docsPath>
 *   { label, href,     position?, className?, 'aria-label'? } -> link (internal or external, auto-detected from `href`)
 *   { html,            position?, className? }              -> raw HTML item (escape hatch)
 *   Pass-through: any object that already looks like a raw Docusaurus navbar item
 *
 * Footer link items share the same `{ label, href }` shape; `href` values
 * beginning with `http://`, `https://`, `//`, `mailto:` or `tel:` are
 * treated as external and passed to Docusaurus as `{ href }`, everything
 * else is treated as an internal path and passed as `{ to }` so Docusaurus
 * applies baseUrl and client-side routing.
 */
const path = require('path');
const fs = require('fs');

/**
 * Default first-doc URL from Docusaurus docs `routeBasePath` (e.g. `docs/intro.md` →
 * `intro` slug). Matches `buildDocusaurusConfig`’s `docsRouteBasePath` defaulting.
 * @param {string} [routeBasePath] Same as the docs plugin `routeBasePath` (default `docs`)
 * @returns {string} Site path starting with `/`, e.g. `/docs/intro` or `/intro` at root
 */
function defaultDocsIntroPath(routeBasePath) {
  const base =
    typeof routeBasePath === 'string' && routeBasePath.length
      ? routeBasePath
      : 'docs';
  const trimmed = String(base)
    .trim()
    .replace(/^\/+/, '')
    .replace(/\/+$/, '');
  if (trimmed === '' || trimmed === '.') {
    return '/intro';
  }
  return `/${trimmed.split('/').filter(Boolean).join('/')}/intro`.replace(/\/+/g, '/');
}

// Values beginning with http(s)://, //, mailto: or tel: are treated as
// external. Anything else (typically '/something', '#anchor', or a
// relative path) is considered internal and routed through Docusaurus's
// `to` field so baseUrl + client-side navigation work automatically.
const EXTERNAL_URL_RE = /^(https?:)?\/\/|^mailto:|^tel:/i;
function isExternalUrl(value) {
  return typeof value === 'string' && EXTERNAL_URL_RE.test(value);
}

function mapDocsConfigToRuntime(site, siteDir) {
  const mdxRoot = typeof site.mdxRoot === 'string' && site.mdxRoot.length ? site.mdxRoot : './docs';
  const absMdxRoot = path.resolve(siteDir, mdxRoot);
  if (!fs.existsSync(absMdxRoot)) {
    throw new Error(
      `[@bndynet/docs] mdxRoot does not exist: ${absMdxRoot} (mdxRoot: ${mdxRoot}).`
    );
  }
  const docsPathRelative = (path.relative(siteDir, absMdxRoot) || '.').split(path.sep).join('/');

  const nav = Array.isArray(site.nav) ? site.nav : [];

  // Build navbar items. For each nav item with `docsPath`, emit a docSidebar navbar item
  // whose sidebarId is the label (the sidebars.cjs loader builds matching autogenerated sidebars).
  const docsMenus = [];
  const menus = [];
  for (const raw of nav) {
    if (!raw || typeof raw !== 'object') continue;
    const position = raw.position || 'left';

    if (typeof raw.docsPath === 'string') {
      const sidebarId = raw.label || raw.docsPath;
      docsMenus.push({ label: sidebarId, docsPath: raw.docsPath });
      menus.push({
        type: 'docSidebar',
        sidebarId,
        position,
        label: raw.label || sidebarId,
        className: raw.className,
      });
      continue;
    }

    if (typeof raw.href === 'string') {
      const base = {
        label: raw.label,
        position,
        className: raw.className,
        'aria-label': raw['aria-label'],
      };
      menus.push(
        isExternalUrl(raw.href) ? { ...base, href: raw.href } : { ...base, to: raw.href },
      );
      continue;
    }

    if (typeof raw.html === 'string') {
      menus.push({ type: 'html', value: raw.html, position, className: raw.className });
      continue;
    }

    // Fallback: pass-through unknown item (advanced use).
    menus.push({ ...raw, position });
  }

  const blog = site.blog !== false;
  const docMenuLabel = site.docMenuLabel || 'Docs';

  const hero = normalizeHero(site);

  const baseApp = {
    staticDirectories: site.staticDirectories,
    url: site.url,
    baseUrl: site.baseUrl,
    logoUrl: site.logo,
    name: site.name || site.title,
    title: site.title,
    tagline: site.tagline || '',
    copyright: site.copyright,
    docMenuLabel,
    menus,
    docsMenus,
    hero,
  };

  const footerLinks = Array.isArray(site.footer?.links) && site.footer.links.length
    ? site.footer.links.map(normalizeFooterColumn)
    : buildDefaultFooter({ ...baseApp, site });

  const app = {
    ...baseApp,
    footerLinks,
    externalStylesheets: site.externalStylesheets || [],
    externalScripts: site.externalScripts || [],
  };

  return { app, docsPathRelative, blog };
}

function buildDefaultFooter(p) {
  return [];
}

/**
 * Normalize one footer column. Item-level transformations:
 *   { label, href }  -> { label, to } when internal, else { label, href } (external)
 *   { html }         -> passed through untouched
 *   Anything else    -> passed through untouched (advanced escape hatch).
 */
function normalizeFooterColumn(column) {
  if (!column || typeof column !== 'object') return column;
  const items = Array.isArray(column.items) ? column.items.map(normalizeFooterItem) : column.items;
  return { ...column, items };
}

function normalizeFooterItem(item) {
  if (!item || typeof item !== 'object') return item;
  if (typeof item.html === 'string') return item;
  if (typeof item.href !== 'string') return item;
  const { href, ...rest } = item;
  return isExternalUrl(href) ? { ...rest, href } : { ...rest, to: href };
}

/**
 * Normalize `site.hero` into the shape consumed by the packaged homepage.
 *
 * Defaults (when fields are omitted):
 *   - variant: 'primary'
 *   - hidden: false
 *   - button:  { label: 'Browse the docs →', href: … } with `href` from
 *              `defaultDocsIntroPath(docsRouteBasePath)` (e.g. `/docs/intro` or `/intro` at root)
 *   - link:    undefined (nothing rendered below the button)
 *
 * Unknown/invalid fields are dropped so the runtime never has to branch on
 * types. `background.image` is left untouched here — baseUrl rewriting
 * happens downstream in buildDocusaurusConfig where `baseUrl` is known.
 */
function normalizeHero(site) {
  const raw = site && typeof site.hero === 'object' && site.hero !== null ? site.hero : {};

  const defaultIntroHref = defaultDocsIntroPath(site && site.docsRouteBasePath);

  const allowedVariants = new Set(['primary', 'dark', 'secondary', 'none']);
  const variant = allowedVariants.has(raw.variant) ? raw.variant : 'primary';

  const rawBg = raw.background && typeof raw.background === 'object' ? raw.background : null;
  const background = rawBg
    ? {
        color: typeof rawBg.color === 'string' && rawBg.color ? rawBg.color : undefined,
        image: typeof rawBg.image === 'string' && rawBg.image ? rawBg.image : undefined,
        overlay: typeof rawBg.overlay === 'string' && rawBg.overlay ? rawBg.overlay : undefined,
      }
    : undefined;
  // Drop the object entirely when every field is empty so the runtime can
  // do a simple truthiness check.
  const backgroundClean =
    background && (background.color || background.image || background.overlay)
      ? background
      : undefined;

  const defaultButton = {
    label: 'Browse the docs →',
    href: defaultIntroHref,
  };
  const button =
    raw.button === false
      ? false
      : normalizeHeroButton(raw.button) || defaultButton;

  const link = normalizeHeroLink(raw.link) || undefined;

  return {
    title: typeof raw.title === 'string' && raw.title ? raw.title : undefined,
    subtitle: typeof raw.subtitle === 'string' && raw.subtitle ? raw.subtitle : undefined,
    variant,
    background: backgroundClean,
    button,
    link,
    hidden: raw.hidden === true,
  };
}

function normalizeHeroButton(raw) {
  if (!raw || typeof raw !== 'object') return null;
  const label = typeof raw.label === 'string' && raw.label ? raw.label : null;
  const href = typeof raw.href === 'string' && raw.href ? raw.href : null;
  if (!label || !href) return null;
  return { label, href };
}

function normalizeHeroLink(raw) {
  if (!raw || typeof raw !== 'object') return null;
  const label = typeof raw.label === 'string' && raw.label ? raw.label : null;
  const href = typeof raw.href === 'string' && raw.href ? raw.href : null;
  if (!label || !href) return null;
  return { label, href };
}

module.exports = { mapDocsConfigToRuntime, defaultDocsIntroPath };
